export interface HSVColor {
    h: number
    s: number
    v: number
    a: number
}

export interface RGBColor {
    r: number
    g: number
    b: number
    a: number
}

export interface HSLColor {
    h: number
    s: number
    l: number
    a: number
}

export type ColorFormat = 'hex' | 'rgb' | 'hsl'

const HEX_SHORT_RE = /^#([a-f\d])([a-f\d])([a-f\d])([a-f\d])?$/i
const HEX_LONG_RE = /^#([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})?$/i
const RGB_RE = /^rgba?\(\s*(\d{1,3})\s*,\s*(\d{1,3})\s*,\s*(\d{1,3})\s*(?:,\s*([\d.]+)\s*)?\)$/i
const HSL_RE = /^hsla?\(\s*(\d{1,3})\s*,\s*([\d.]+)%\s*,\s*([\d.]+)%\s*(?:,\s*([\d.]+)\s*)?\)$/i

function clamp(value: number, min: number, max: number): number {
    return Math.min(max, Math.max(min, value))
}

function toHex2(value: number): string {
    return clamp(Math.round(value), 0, 255).toString(16).padStart(2, '0')
}

export function hsvToRgb(hsv: HSVColor): RGBColor {
    const h = ((hsv.h % 360) + 360) % 360
    const s = clamp(hsv.s, 0, 100) / 100
    const v = clamp(hsv.v, 0, 100) / 100
    const c = v * s
    const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
    const m = v - c
    let r: number
    let g: number
    let b: number
    if (h < 60) { r = c; g = x; b = 0 }
    else if (h < 120) { r = x; g = c; b = 0 }
    else if (h < 180) { r = 0; g = c; b = x }
    else if (h < 240) { r = 0; g = x; b = c }
    else if (h < 300) { r = x; g = 0; b = c }
    else { r = c; g = 0; b = x }
    return {
        r: Math.round((r + m) * 255),
        g: Math.round((g + m) * 255),
        b: Math.round((b + m) * 255),
        a: clamp(hsv.a, 0, 1),
    }
}

export function rgbToHsv(rgb: RGBColor): HSVColor {
    const r = clamp(rgb.r, 0, 255) / 255
    const g = clamp(rgb.g, 0, 255) / 255
    const b = clamp(rgb.b, 0, 255) / 255
    const max = Math.max(r, g, b)
    const min = Math.min(r, g, b)
    const delta = max - min
    let h = 0
    if (delta > 0) {
        if (max === r) h = 60 * (((g - b) / delta) % 6)
        else if (max === g) h = 60 * ((b - r) / delta + 2)
        else h = 60 * ((r - g) / delta + 4)
    }
    if (h < 0) h += 360
    const s = max === 0 ? 0 : (delta / max) * 100
    const v = max * 100
    return {
        h: Math.round(h),
        s: Math.round(s * 10) / 10,
        v: Math.round(v * 10) / 10,
        a: clamp(rgb.a, 0, 1),
    }
}

export function rgbToHsl(rgb: RGBColor): HSLColor {
    const r = clamp(rgb.r, 0, 255) / 255
    const g = clamp(rgb.g, 0, 255) / 255
    const b = clamp(rgb.b, 0, 255) / 255
    const max = Math.max(r, g, b)
    const min = Math.min(r, g, b)
    const delta = max - min
    let h = 0
    if (delta > 0) {
        if (max === r) h = 60 * (((g - b) / delta) % 6)
        else if (max === g) h = 60 * ((b - r) / delta + 2)
        else h = 60 * ((r - g) / delta + 4)
    }
    if (h < 0) h += 360
    const l = (max + min) / 2
    const s = delta === 0 ? 0 : delta / (1 - Math.abs(2 * l - 1))
    return {
        h: Math.round(h),
        s: Math.round(s * 1000) / 10,
        l: Math.round(l * 1000) / 10,
        a: clamp(rgb.a, 0, 1),
    }
}

export function hslToRgb(hsl: HSLColor): RGBColor {
    const h = ((hsl.h % 360) + 360) % 360
    const s = clamp(hsl.s, 0, 100) / 100
    const l = clamp(hsl.l, 0, 100) / 100
    const c = (1 - Math.abs(2 * l - 1)) * s
    const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
    const m = l - c / 2
    let r: number
    let g: number
    let b: number
    if (h < 60) { r = c; g = x; b = 0 }
    else if (h < 120) { r = x; g = c; b = 0 }
    else if (h < 180) { r = 0; g = c; b = x }
    else if (h < 240) { r = 0; g = x; b = c }
    else if (h < 300) { r = x; g = 0; b = c }
    else { r = c; g = 0; b = x }
    return {
        r: Math.round((r + m) * 255),
        g: Math.round((g + m) * 255),
        b: Math.round((b + m) * 255),
        a: clamp(hsl.a, 0, 1),
    }
}

export function hsvToHex(hsv: HSVColor): string {
    return hsvToHexAlpha({ ...hsv, a: 1 })
}

export function hsvToHexAlpha(hsv: HSVColor): string {
    const rgb = hsvToRgb(hsv)
    const alpha = clamp(hsv.a, 0, 1)
    const base = `#${toHex2(rgb.r)}${toHex2(rgb.g)}${toHex2(rgb.b)}`
    if (alpha < 1) {
        return `${base}${toHex2(alpha * 255)}`
    }
    return base
}

export function hexToHsv(hex: string): HSVColor | null {
    const rgb = hexToRgb(hex)
    return rgb ? rgbToHsv(rgb) : null
}

export function hexToRgb(hex: string): RGBColor | null {
    const trimmed = hex.trim()
    const shortMatch = trimmed.match(HEX_SHORT_RE)
    if (shortMatch) {
        const r = parseInt(shortMatch[1] + shortMatch[1], 16)
        const g = parseInt(shortMatch[2] + shortMatch[2], 16)
        const b = parseInt(shortMatch[3] + shortMatch[3], 16)
        const a = shortMatch[4] ? parseInt(shortMatch[4] + shortMatch[4], 16) / 255 : 1
        return { r, g, b, a }
    }
    const longMatch = trimmed.match(HEX_LONG_RE)
    if (longMatch) {
        const r = parseInt(longMatch[1], 16)
        const g = parseInt(longMatch[2], 16)
        const b = parseInt(longMatch[3], 16)
        const a = longMatch[4] ? parseInt(longMatch[4], 16) / 255 : 1
        return { r, g, b, a }
    }
    return null
}

export function parseColor(color: string): HSVColor | null {
    if (!color || typeof color !== 'string') return null
    const trimmed = color.trim()
    if (trimmed.startsWith('#')) {
        return hexToHsv(trimmed)
    }
    const rgbMatch = trimmed.match(RGB_RE)
    if (rgbMatch) {
        const r = clamp(parseInt(rgbMatch[1], 10), 0, 255)
        const g = clamp(parseInt(rgbMatch[2], 10), 0, 255)
        const b = clamp(parseInt(rgbMatch[3], 10), 0, 255)
        const a = rgbMatch[4] !== undefined ? clamp(parseFloat(rgbMatch[4]), 0, 1) : 1
        return rgbToHsv({ r, g, b, a })
    }
    const hslMatch = trimmed.match(HSL_RE)
    if (hslMatch) {
        const h = clamp(parseInt(hslMatch[1], 10), 0, 360)
        const s = clamp(parseFloat(hslMatch[2]), 0, 100)
        const l = clamp(parseFloat(hslMatch[3]), 0, 100)
        const a = hslMatch[4] !== undefined ? clamp(parseFloat(hslMatch[4]), 0, 1) : 1
        return rgbToHsv(hslToRgb({ h, s, l, a }))
    }
    return null
}

export function isValidColor(color: string): boolean {
    return parseColor(color) !== null
}

export function formatColor(hsv: HSVColor, format: ColorFormat, showAlpha = false): string {
    if (format === 'hex') {
        return showAlpha ? hsvToHexAlpha(hsv) : hsvToHex(hsv)
    }
    if (format === 'rgb') {
        const rgb = hsvToRgb(hsv)
        if (showAlpha && hsv.a < 1) {
            return `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${Math.round(hsv.a * 100) / 100})`
        }
        return `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`
    }
    const hsl = rgbToHsl(hsvToRgb(hsv))
    if (showAlpha && hsv.a < 1) {
        return `hsla(${hsl.h}, ${hsl.s}%, ${hsl.l}%, ${Math.round(hsv.a * 100) / 100})`
    }
    return `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`
}

export function normalizeColor(color: string): string | null {
    const hsv = parseColor(color)
    if (!hsv) return null
    const hasAlpha = hsv.a < 1
    return formatColor(hsv, 'hex', hasAlpha)
}

/**
 * Environment detection utilities for SSR compatibility.
 * Use these instead of scattered `typeof document/window` checks.
 */

/** Whether the code is running in a browser environment (not SSR). */
export const isClient = typeof window !== 'undefined'

/** Whether `document` is available. */
export const hasDocument = typeof document !== 'undefined'

/** Whether `localStorage` is available (may be blocked in Safari private mode). */
export const hasLocalStorage = typeof localStorage !== 'undefined'

/** Whether `document.body` is available for imperative mounting. */
export function canUseDocumentBody(): boolean {
    return hasDocument && document.body !== null
}

/** Whether IntersectionObserver is available. */
export const hasIntersectionObserver = isClient && typeof window.IntersectionObserver !== 'undefined'

type AudioContextConstructor = typeof AudioContext
type ResizeObserverConstructor = typeof ResizeObserver
type MutationObserverConstructor = typeof MutationObserver

export interface ViewportSize {
    width: number
    height: number
}

/** Get the available AudioContext constructor, including Safari's prefixed API. */
export function getAudioContextCtor(): AudioContextConstructor | null {
    if (!isClient) return null
    return window.AudioContext
        ?? (window as Window & typeof globalThis & { webkitAudioContext?: AudioContextConstructor }).webkitAudioContext
        ?? null
}

/** Get the available ResizeObserver constructor. */
export function getResizeObserverCtor(): ResizeObserverConstructor | null {
    if (!isClient) return null
    return window.ResizeObserver ?? null
}

/** Get the available MutationObserver constructor. */
export function getMutationObserverCtor(): MutationObserverConstructor | null {
    if (!isClient) return null
    return window.MutationObserver ?? null
}

/** Get the current device pixel ratio with an SSR-safe fallback. */
export function getDevicePixelRatio(): number {
    if (!isClient) return 1
    return window.devicePixelRatio || 1
}

/** Get viewport dimensions with an SSR-safe fallback. */
export function getViewportSize(): ViewportSize {
    if (!isClient) return { width: 0, height: 0 }
    return {
        width: window.innerWidth,
        height: window.innerHeight,
    }
}

/** Create a canvas element when the DOM supports it. */
export function createCanvasElement(): HTMLCanvasElement | null {
    if (!hasDocument) return null
    try {
        return document.createElement('canvas')
    } catch {
        return null
    }
}

/** Get a 2D rendering context without leaking capability errors to callers. */
export function getCanvas2DContext(canvas: HTMLCanvasElement): CanvasRenderingContext2D | null {
    try {
        return canvas.getContext('2d')
    } catch {
        return null
    }
}

/**
 * Safely get a value from localStorage.
 * Returns `null` if localStorage is unavailable or the key doesn't exist.
 */
export function safeGetStorageItem(key: string): string | null {
    try {
        if (!hasLocalStorage) return null
        return localStorage.getItem(key)
    } catch {
        return null
    }
}

/**
 * Safely set a value in localStorage.
 * Silently fails if localStorage is unavailable (e.g. Safari private mode, storage full).
 */
export function safeSetStorageItem(key: string, value: string): void {
    try {
        if (!hasLocalStorage) return
        localStorage.setItem(key, value)
    } catch {
        // Storage full or blocked (e.g. Safari private mode)
    }
}
